// Date Formatter
const now = new Date();
const mountainTime = new Date(now.toLocaleString("en-US", {timeZone: "America/Denver"}));
const yesterday = new Date(mountainTime.getTime() - 24*60*60*1000);

try {
  const output = {
    today: mountainTime.toLocaleDateString('en-US', { 
      weekday: 'long', 
      year: 'numeric', 
      month: 'long', 
      day: 'numeric' 
    }),
    dayOfWeek: mountainTime.toLocaleDateString('en-US', { weekday: 'long' }),
    usccbDate: [
      String(mountainTime.getMonth() + 1).padStart(2, '0'),
      String(mountainTime.getDate()).padStart(2, '0'), 
      String(mountainTime.getFullYear()).slice(-2)
    ].join(''),
    monthDay: `${mountainTime.getMonth() + 1}/${mountainTime.getDate()}`,
    theme: {
      'Sunday': 'Worship & Community',
      'Monday': 'Humility & Simplicity',
      'Tuesday': 'Stability',
      'Wednesday': 'Listening',
      'Thursday': 'Hospitality & Kindness',
      'Friday': 'Sacrifice & Repentance',
      'Saturday': 'Rest & Beauty'
    }[mountainTime.toLocaleDateString('en-US', { weekday: 'long' })]
  };

  return output;

} catch (error) {
  return {
    today: 'Date unavailable',
    dayOfWeek: 'Today',
    theme: 'Prayer',
    monthDay: '1/1'
  };
}

// Saints Lookup
const dateInfo = $json;

try {
  const saintsDatabase = {
    '8/26': { name: 'Daily Weekday', type: 'Weekday', quote: 'Be it done unto me according to your word.', intro: 'Today we focus on living out our baptismal call in ordinary circumstances.' },
    '8/27': { name: 'Monica', type: 'Memorial', quote: 'Nothing is far from God.', intro: 'Mother of St. Augustine, she prayed for her son\'s conversion for many years before seeing it fulfilled.' }
  };

  const currentDate = dateInfo.monthDay;
  const todaySaint = saintsDatabase[currentDate];

  let saint = todaySaint || {
    name: 'Weekday in Ordinary Time',
    type: 'Weekday',
    intro: 'A day to grow in holiness through ordinary work and prayer.'
  };

  return {
    ...dateInfo,
    saint: saint
  };

} catch (error) {
  return {
    ...dateInfo,
    saint: {
      name: 'Daily Saint',
      intro: 'Saint information unavailable'
    }
  };
}

// Readings Lookup
const data = $json;

try {
  const readingsDatabase = {
    '8/26': { firstReading: '1 Thessalonians 2:1-8', psalm: 'Psalm 139:1-3, 4-6', gospel: 'Matthew 23:23-26', season: 'Ordinary Time' },
    '8/27': { firstReading: '1 Thessalonians 2:9-13', psalm: 'Psalm 139:7-8, 9-10, 11-12ab', gospel: 'Matthew 23:27-32', season: 'Ordinary Time' }
  };

  const currentDate = data.monthDay;
  let todayReadings = readingsDatabase[currentDate] || {
    firstReading: 'Check USCCB for readings',
    psalm: 'Psalm 23:1-6',
    gospel: 'John 3:16-21',
    season: 'Ordinary Time'
  };

  todayReadings.usccbLink = `https://bible.usccb.org/bible/readings/${data.usccbDate}.cfm`;

  return {
    ...data,
    readings: todayReadings
  };

} catch (error) {
  return {
    ...data,
    readings: {
      firstReading: 'Scripture reading unavailable',
      psalm: 'Psalm unavailable',
      gospel: 'Gospel reading unavailable'
    }
  };
}

