// Data Merger - Combine AI response with original workflow data
const aiResponse = $json; // AI output (only has 'text' field)
const allInputs = $input.all(); // Get all previous data

try {
  console.log('=== DATA MERGER START ===');
  console.log('AI response keys:', Object.keys(aiResponse));
  console.log('Number of inputs:', allInputs.length);

  // Find the workflow data (should be input 0 - the readings data)
  let workflowData = {};
  if (allInputs.length > 0) {
    workflowData = allInputs[0]?.json || {};
    console.log('✅ Found workflow data with keys:', Object.keys(workflowData));
    console.log('Has readings:', !!workflowData.readings);
  } else {
    console.log('❌ No workflow data found in inputs');
  }

  // Parse AI response
  let aiContent = {};
  try {
    const aiText = aiResponse?.text || aiResponse?.message || '';
    if (aiText) {
      const cleanText = aiText.replace(/```json\n?/g, "").replace(/```\n?/g, "").trim();
      aiContent = JSON.parse(cleanText);
      console.log('✅ Parsed AI content successfully');
    }
  } catch (parseError) {
    console.log('AI parse error, using fallback:', parseError.message);
    aiContent = {
      reflection: `Today's theme is ${workflowData.theme || 'Prayer'}. Take time to reflect on this Benedictine virtue.`,
      challenge: 'Spend 10 minutes in silent prayer today, listening for God\'s voice.',
      prayer: 'Lord, help us follow the example of the saints and grow in holiness. Amen.'
    };
  }

  // Combine everything
  const combinedData = {
    ...workflowData,  // All the original data (date, saint, readings)
    ai: aiContent     // Add AI content under 'ai' key
  };

  console.log('✅ Data merger complete. Final keys:', Object.keys(combinedData));
  console.log('Final has readings:', !!combinedData.readings);
  console.log('Final has AI:', !!combinedData.ai);

  return combinedData;

} catch (error) {
  console.error('Data merger error:', error.message);
  return {
    error: 'Data merge failed',
    aiResponse: aiResponse,
    inputs: allInputs
  };
}

// Final Email Compiler - Now has both workflow data AND AI content
const allData = $json;

try {
  console.log('=== EMAIL COMPILER FINAL ===');
  console.log('Data keys:', Object.keys(allData));
  console.log('Has readings:', !!allData.readings);
  console.log('Has AI:', !!allData.ai);

  // Extract all data
  const dateInfo = {
    today: allData.today || 'Today',
    dayOfWeek: allData.dayOfWeek || 'Today',
    theme: allData.theme || 'Prayer'
